import { useState, useEffect } from "react";

function App() {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [zoom, setZoom] = useState(false);
  const [animatedScore, setAnimatedScore] = useState(0);

  const claimId = `CLM-${Date.now()}`;

  useEffect(() => {
    if (result) {
      let start = 0;
      const end = result.fraud_confidence_score;
      const duration = 1000;
      const stepTime = 20;
      const step = (end - start) / (duration / stepTime);

      const interval = setInterval(() => {
        start += step;
        if (start >= end) {
          start = end;
          clearInterval(interval);
        }
        setAnimatedScore(Math.round(start));
      }, stepTime);
    }
  }, [result]);

  const riskLevel = (score) => {
    if (score <= 40) return "Low Risk";
    if (score <= 75) return "Medium Risk";
    return "High Risk";
  };

  const gaugeColor = (score) => {
    if (score <= 50) return "#22c55e";
    if (score <= 80) return "#f59e0b";
    return "#ef4444";
  };

  const verdictColor = (verdict) => {
    if (!verdict) return "#555";
    if (verdict.toLowerCase() === "fraud") return "#ef4444";
    if (verdict.toLowerCase() === "suspicious") return "#f59e0b";
    return "#22c55e";
  };

  const handleFileChange = (e) => {
    setError(null);
    const selected = e.target.files[0];
    setFile(selected);
    setPreview(selected ? URL.createObjectURL(selected) : null);
    setResult(null);
    setAnimatedScore(0);
  };

  const handleUpload = async () => {
    if (!file) return setError("Please select an image first.");

    const formData = new FormData();
    formData.append("file", file);

    setLoading(true);
    setResult(null);
    setError(null);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", {
        method: "POST",
        body: formData,
      });
      if (!response.ok) throw new Error("Server error!");
      const data = await response.json();
      setResult(data);
    } catch (err) {
      setError(err.message || "Something went wrong!");
    }

    setLoading(false);
  };

  const handleReset = () => {
    setFile(null);
    setPreview(null);
    setResult(null);
    setError(null);
    setZoom(false);
    setAnimatedScore(0);
  };

  const downloadReport = () => {
    if (!result) return;
    const blob = new Blob([JSON.stringify(result, null, 2)], {
      type: "application/json",
    });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `audit_report_${claimId}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <header style={styles.header}>
          <h1 style={styles.logo}>ClaimPilot AI</h1>
          <p style={styles.tagline}>Smart Vehicle Damage Assessment</p>

          <div style={styles.statusIndicator}>
            <span style={styles.statusDot}></span>
            AI System Active
          </div>
        </header>

        <div style={styles.uploadCard}>
          {preview && (
            <img
              src={preview}
              alt="preview"
              style={zoom ? styles.previewZoom : styles.previewImage}
              onClick={() => setZoom(!zoom)}
            />
          )}

          <label style={styles.uploadLabel}>
            {file ? file.name : "Click or drag to upload image"}
            <input
              type="file"
              accept="image/*"
              style={{ display: "none" }}
              onChange={handleFileChange}
            />
          </label>

          <div style={{ display: "flex", justifyContent: "center", gap: "10px" }}>
            <button
              onClick={handleUpload}
              disabled={loading}
              style={loading ? styles.buttonDisabled : styles.button}
            >
              {loading ? "Analyzing..." : "Run AI Audit"}
            </button>

            {file && (
              <button onClick={handleReset} style={styles.resetButton}>
                Reset
              </button>
            )}
          </div>

          {error && <p style={styles.error}>{error}</p>}
        </div>

        {result && (
          <div style={styles.resultCard}>
            <h2>Audit Summary</h2>

            <p style={{ fontSize: "13px", color: "#555" }}>
              Claim ID: <strong>{claimId}</strong>
            </p>

            <div style={styles.stats}>
              <div style={styles.statBox}>
                <p>Total Estimate</p>
                <h3>PKR {result.total_estimate_pkr}</h3>
              </div>

              <div style={styles.statBox}>
                <p>Fraud Score</p>
                <svg viewBox="0 0 36 36" style={styles.gauge}>
                  <path
                    style={{ stroke: "#eee" }}
                    d="M18 2.0845
                       a 15.9155 15.9155 0 0 1 0 31.831
                       a 15.9155 15.9155 0 0 1 0 -31.831"
                    fill="none"
                    strokeWidth="2.8"
                  />
                  <path
                    style={{ stroke: gaugeColor(animatedScore) }}
                    strokeDasharray={`${animatedScore}, 100`}
                    d="M18 2.0845
                       a 15.9155 15.9155 0 0 1 0 31.831
                       a 15.9155 15.9155 0 0 1 0 -31.831"
                    fill="none"
                    strokeWidth="2.8"
                  />
                  <text x="18" y="20.35" style={styles.gaugeText}>
                    {animatedScore}%
                  </text>
                </svg>

                <p style={{ color: gaugeColor(animatedScore), fontWeight: "600" }}>
                  {riskLevel(animatedScore)}
                </p>
              </div>

              <div
                style={{
                  ...styles.statBox,
                  color: verdictColor(result.verdict),
                }}
              >
                <p>Verdict</p>
                <h3>{result.verdict}</h3>
              </div>
            </div>

            <div style={styles.details}>
              <h3>Fraud Analysis</h3>
              <p>{result.fraud_analysis || "No fraud detected."}</p>

              <h3>Risk Breakdown</h3>
              <div style={styles.progressBar}>
                <div
                  style={{
                    ...styles.progressFill,
                    width: `${animatedScore}%`,
                  }}
                />
              </div>

              <h3>Damaged Parts</h3>
              {result.damaged_parts?.length ? (
                <ul>
                  {result.damaged_parts.map((part, index) => (
                    <li key={index} style={styles.partItem}>
                      {part}
                      <span style={styles.severityTag}>Moderate</span>
                    </li>
                  ))}
                </ul>
              ) : (
                <p>No parts detected.</p>
              )}

              <h3>AI Confidence Explanation</h3>
              <p>
                The fraud confidence score is calculated using image anomaly
                detection, metadata checks, and repair cost deviation patterns.
              </p>

              <button onClick={downloadReport} style={styles.downloadButton}>
                Download Audit Report
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

